import { z } from 'zod';
import { WorkspaceRoleSchema } from '../../workspaces/types.js';
export const CollaboratorSchema = z.looseObject({
    id: z.string(),
    email: z.string(),
    fullName: z.string(),
    timezone: z.string(),
    imageId: z.string().nullable(),
});
/** Available collaborator statuses. */
export const COLLABORATOR_STATUSES = ['active', 'invited'];
export const CollaboratorStateSchema = z.looseObject({
    userId: z.string(),
    projectId: z.string(),
    state: z.enum(COLLABORATOR_STATUSES),
    isDeleted: z.boolean(),
    workspaceRole: WorkspaceRoleSchema.optional(),
});
